#include <mpi.h>
#include <omp.h>
#include <vector>
#include <cmath>
#include <algorithm>

struct Point {
    double x, y;
};

double distance(Point const& p1, Point const& p2) {
    return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

// Function to compute the convex hull using Graham's scan algorithm
std::vector<Point> grahamScan(const std::vector<Point>& points) {
    // Sort points by polar angle with respect to the lowest point
    auto compare = [](const Point& a, const Point& b) {
        return atan2(a.y - points[0].y, a.x - points[0].x) < atan2(b.y - points[0].y, b.x - points[0].x);
    };
    std::sort(points.begin(), points.end(), compare);

    // Initialize the convex hull with the first three points
    std::vector<Point> hull = {points[0], points[1]};
    for (size_t i = 2; i < points.size(); ++i) {
        while (hull.size() > 1 && crossProduct(hull[hull.size()-2], hull.back(), points[i]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(points[i]);
    }

    return hull;
}

// Function to compute the cross product of vectors AB and BC
double crossProduct(Point A, Point B, Point C) {
    return (B.x - A.x) * (C.y - B.y) - (B.y - A.y) * (C.x - B.x);
}

// Function to compute the perimeter of a convex hull
double convexHullPerimeter(const std::vector<Point>& points) {
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(MPI_COMM_SIZE, &size);

    // Divide points among ranks using round-robin distribution
    std::vector<Point> local_points(points.size() / size + (rank < points.size() % size));
    for (int i = rank; i < points.size(); i += size) {
        local_points[i - rank] = points[i];
    }

    // Compute the convex hull of the local points using OpenMP
    std::vector<Point> local_hull;
#pragma omp parallel
    {
        std::vector<Point> temp_hull = grahamScan(local_points);
        #pragma omp critical
        {
            if (temp_hull.size() > local_hull.size()) {
                local_hull = temp_hull;
            }
        }
    }

    // Gather all local convex hulls to rank 0 and merge them into a global convex hull
    std::vector<Point> global_hulls[size];
    MPI_Gather(local_hull.data(), local_hull.size(), MPI_DOUBLE, &global_hulls[0][0], local_hull.size(), MPI_DOUBLE, 0, MPI_COMM_WORLD);

    if (rank == 0) {
        // Merge all local convex hulls into a single global convex hull
        std::vector<Point> global_points;
        for (int i = 0; i < size; ++i) {
            global_points.insert(global_points.end(), global_hulls[i].begin(), global_hulls[i].end());
        }
        std::sort(global_points.begin(), global_points.end());

        // Compute the convex hull of the merged points
        std::vector<Point> final_hull = grahamScan(global_points);

        // Compute and return the perimeter of the final convex hull
        double perimeter = 0.0;
        for (size_t i = 1; i < final_hull.size(); ++i) {
            perimeter += distance(final_hull[i-1], final_hull[i]);
        }
        perimeter += distance(final_hull.back(), final_hull.front());

        return perimeter;
    } else {
        return 0.0;
    }
}
