double convexHullPerimeter(std::vector<Point> const& points) {
	int numRanks = MPI_Comm_size(MPI_COMM_WORLD);
	int rank = MPI_Comm_rank(MPI_COMM_WORLD);

	// Each process computes a portion of the convex hull
	std::vector<Point> localPoints(points.size() / numRanks);
	if (rank < points.size() % numRanks) {
		localPoints.resize(localPoints.size() + 1);
	}
	for (int i = rank; i < points.size(); i += numRanks) {
		localPoints[i - rank] = points[i];
	}

	double localPerimeter = 0.0;
	omp_set_num_threads(4); // Set the number of OpenMP threads
	#pragma omp parallel for reduction(+:localPerimeter)
	for (int i = 1; i < localPoints.size(); ++i) {
		localPerimeter += distance(localPoints[i - 1], localPoints[i]);
	}

	double globalPerimeter = 0.0;
	if (rank == 0) {
		globalPerimeter = localPerimeter;
	} else {
		MPI_Send(&localPerimeter, 1, MPI_DOUBLE, 0, 0, MPI_COMM_WORLD);
	}
	for (int i = 1; i < numRanks; ++i) {
		if (rank == i) {
			MPI_Recv(&globalPerimeter, 1, MPI_DOUBLE, 0, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
		} else if (rank > i) {
			MPI_Send(&localPerimeter, 1, MPI_DOUBLE, i - 1, 0, MPI_COMM_WORLD);
		}
	}

	return globalPerimeter;
}
